mapper.select:
SELECT VRA.RESERVATION_ID, VRA.OPEN_AT, VRA.CAFE_ID, VRA.CAFE_NAME, VRA.ROOM_ID, VRA.ROOM_NAME, VRA.LEADER_ID, UA.NICKNAME AS LEADER_NICKNAME, VRA.TOTAL_MEMBER, FN_GET_ATTEND_STATUS(VRA.RESERVATION_ID, VRA.LEADER_ID) AS STATUS_NAME FROM VW_RESERVATION_ALL VRA JOIN CAFE C ON VRA.CAFE_ID = C.CAFE_ID JOIN USER_ACCOUNT UA ON VRA.LEADER_ID = UA.USER_ID WHERE C.USER_ID = #{ownerUserId}
AND VRA.OPEN_AT < SYSDATE
ORDER BY VRA.OPEN_AT DESC

SELECT VRA.RESERVATION_ID, VRA.OPEN_AT, VRA.CAFE_ID, VRA.CAFE_NAME, VRA.ROOM_ID, VRA.ROOM_NAME, VRA.LEADER_ID, UA.NICKNAME AS LEADER_NICKNAME, VRA.TOTAL_MEMBER, FN_GET_ATTEND_STATUS(VRA.RESERVATION_ID, VRA.LEADER_ID) AS STATUS_NAME FROM VW_RESERVATION_ALL VRA JOIN V_ACTIVE_MANAGER VAM ON VAM.CAFE_ID = VRA.CAFE_ID JOIN USER_ACCOUNT UA ON VRA.LEADER_ID = UA.USER_ID WHERE VAM.USER_ID = #{managerUserId}
AND VRA.OPEN_AT < SYSDATE
ORDER BY VRA.OPEN_AT DESC
